public void solveSudoku(char[][] board) {
    boolean[][] rows = new boolean[9][9];
    boolean[][] cols = new boolean[9][9];
    boolean[][] boxes = new boolean[9][9];

    for (int i = 0; i < 9; i++) {
        for (int j = 0; j < 9; j++) {
            if (board[i][j] != '.') {
                int d = board[i][j] - '1';
                int box = (i / 3) * 3 + j / 3;
                rows[i][d] = cols[j][d] = boxes[box][d] = true;
            }
        }
    }
    solve(board, rows, cols, boxes, 0, 0);
}

private boolean solve(char[][] board, boolean[][] rows, boolean[][] cols,
                      boolean[][] boxes, int r, int c) {
    if (r == 9) return true;
    int nr = (c == 8) ? r + 1 : r;
    int nc = (c == 8) ? 0 : c + 1;
    if (board[r][c] != '.') return solve(board, rows, cols, boxes, nr, nc);
    int box = (r / 3) * 3 + c / 3;
    for (int d = 0; d < 9; d++) {
        if (!rows[r][d] && !cols[c][d] && !boxes[box][d]) {
            board[r][c] = (char)('1' + d);
            rows[r][d] = cols[c][d] = boxes[box][d] = true;
            if (solve(board, rows, cols, boxes, nr, nc)) return true;
            board[r][c] = '.';
            rows[r][d] = cols[c][d] = boxes[box][d] = false;
        }
    }
    return false;
}

