def solveSudoku(board: list[list[str]]) -> None:
    rows = [[False] * 9 for _ in range(9)]
    cols = [[False] * 9 for _ in range(9)]
    boxes = [[False] * 9 for _ in range(9)]

    for i in range(9):
        for j in range(9):
            if board[i][j] != '.':
                d = int(board[i][j]) - 1
                box = (i // 3) * 3 + j // 3
                rows[i][d] = cols[j][d] = boxes[box][d] = True

    def solve(r: int, c: int) -> bool:
        if r == 9:
            return True
        nr = r + 1 if c == 8 else r
        nc = 0 if c == 8 else c + 1
        if board[r][c] != '.':
            return solve(nr, nc)
        box = (r // 3) * 3 + c // 3
        for d in range(9):
            if not rows[r][d] and not cols[c][d] and not boxes[box][d]:
                board[r][c] = str(d + 1)
                rows[r][d] = cols[c][d] = boxes[box][d] = True
                if solve(nr, nc):
                    return True
                board[r][c] = '.'
                rows[r][d] = cols[c][d] = boxes[box][d] = False
        return False

    solve(0, 0)
